(function($){$(document).ready(function(){$(".approval-toggle").on("change",function(){const t=$(this),e=t.closest("tr").data("id"),s=t.is(":checked");$.ajax({url:showSubmissionsAdmin.ajaxurl,type:"POST",data:{action:"update_submission_approval",nonce:showSubmissionsAdmin.nonce,id:e,approved:s},success:function(e){e.success||(alert("Failed to update approval status."),t.prop("checked",!s))},error:function(){alert("An error occurred."),t.prop("checked",!s)}})}),$(".delete-submission").on("click",function(t){t.preventDefault();if(!confirm("Are you sure you want to delete this submission?"))return;const e=$(this),s=e.data("id");$.ajax({url:showSubmissionsAdmin.ajaxurl,type:"POST",data:{action:"delete_submission",nonce:showSubmissionsAdmin.nonce,id:s},success:function(t){t.success?e.closest("tr").fadeOut(300,function(){$(this).remove()}):alert(t.data||"Failed to delete submission.")},error:function(){alert("An error occurred while trying to delete the submission.")}})})})})(jQuery);